<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Session.php'; require_once __DIR__.'/../includes/Auth.php'; Session::start();Auth::requireAdmin(); $db=Database::getInstance();$msg='';$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){if(!Auth::validateCsrf()){$err='安全验证失败。';}else{$a=$_POST['action']??'';if($a==='add'){$un=trim($_POST['username']??'');$pw=$_POST['password']??'';$em=trim($_POST['email']??'');$rl=$_POST['role']??'admin';if(empty($un)||empty($pw))$err='用户名和密码不能为空。';elseif(strlen($pw)<6)$err='密码至少6个字符。';elseif($db->exists('users','username=?',[$un]))$err='用户名已存在。';else{Auth::createUser($un,$pw,$em?:null,$rl);$msg='用户创建成功。';}}elseif($a==='delete'){$id=(int)($_POST['id']??0);if($id===Auth::id())$err='不能删除自己。';else{$db->delete('users','id=?',[$id]);$msg='用户已删除。';}}elseif($a==='toggle'){$id=(int)($_POST['id']??0);if($id===Auth::id())$err='不能停用自己。';else{$u=$db->fetch("SELECT is_active FROM `users` WHERE id=?",[$id]);$db->update('users',['is_active'=>$u['is_active']?0:1],'id=?',[$id]);$msg='用户状态已更新。';}}}} $users=$db->fetchAll("SELECT id,username,email,role,last_login,is_active,created_at FROM `users` ORDER BY created_at DESC");$cu=Auth::user();?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>用户管理 - <?php echo APP_NAME;?></title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/admin.css" rel="stylesheet"></head><body><div class="admin-layout"><?php include __DIR__.'/sidebar.php';?><main class="main-content"><div class="top-bar"><h2>用户管理</h2><div class="top-bar-right"><span class="user-info"><span class="material-icons">person</span><?php echo e($cu['username']);?></span></div></div><?php if($msg):?><div class="alert alert-success"><?php echo e($msg);?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?php echo e($err);?></div><?php endif;?><div class="card"><div class="card-header"><h3>添加用户</h3></div><div class="card-body"><form method="POST" class="form"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="add"><div class="form-row"><div class="form-group"><label>用户名 *</label><input type="text" name="username" required></div><div class="form-group"><label>邮箱</label><input type="email" name="email"></div></div><div class="form-row"><div class="form-group"><label>密码 *</label><input type="password" name="password" required minlength="6"></div><div class="form-group"><label>角色</label><select name="role"><option value="admin">管理员</option><option value="viewer">观察者</option></select></div></div><button type="submit" class="btn btn-primary">添加用户</button></form></div></div><div class="card"><div class="card-header"><h3>用户列表 (<?php echo count($users);?>)</h3></div><div class="card-body"><table class="table"><thead><tr><th>用户名</th><th>邮箱</th><th>角色</th><th>最后登录</th><th>状态</th><th>操作</th></tr></thead><tbody><?php foreach($users as $u):?><tr><td><?php echo e($u['username']);?></td><td><?php echo e($u['email']??'-');?></td><td><span class="badge badge-<?php echo $u['role']==='admin'?'primary':'secondary';?>"><?php echo $u['role']==='admin'?'管理员':'观察者';?></span></td><td><?php echo e($u['last_login']??'从未登录');?></td><td><span class="badge badge-<?php echo $u['is_active']?'success':'danger';?>"><?php echo $u['is_active']?'启用':'停用';?></span></td><td class="actions"><?php if($u['id']!==Auth::id()):?><form method="POST" style="display:inline"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?php echo $u['id'];?>"><button type="submit" class="btn-sm btn-warning"><?php echo $u['is_active']?'停用':'启用';?></button></form><form method="POST" style="display:inline" onsubmit="return confirm('确定删除？');"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?php echo $u['id'];?>"><button type="submit" class="btn-sm btn-danger">删除</button></form><?php else:?><span class="text-muted">当前用户</span><?php endif;?></td></tr><?php endforeach;?></tbody></table></div></div></main></div></body></html>